import json
from math import ceil

def design_copy_generation_request(product_info, tone, target_audience, model="gpt-4o-mini"):
    system_prompt = f"""あなたは日本のデジタルマーケティングのコピーライター専門家です。

必須ルール:
- ターゲット: {target_audience}
- トーン: {tone}
- 文字数: タイトル20字以内、本文80字以内
- 景品表示法・薬機法に準拠した表現のみ使用
- 根拠のない最上級表現は使わない
- 具体的な数値・ベネフィットを必ず含める"""

    user_prompt = f"""以下の商品の広告コピーを3パターン生成してください。

商品名: {product_info['name']}
カテゴリ: {product_info['category']}
価格: ¥{product_info['price']:,}
特徴: {product_info['features']}
キャンペーン: {product_info.get('campaign', 'なし')}

出力形式:
パターン1【訴求軸: XXX】
タイトル: 
本文: """

    return {
        "model": model,
        "messages": [
            {"role": "system", "content": system_prompt},
            {"role": "user", "content": user_prompt}
        ],
        "temperature": 0.8,
        "max_tokens": 1000,
    }

product = {
    "name": "ビタミンCサプリメント DayBoost",
    "category": "健康食品",
    "price": 3980,
    "features": "高吸収型ビタミンC 1000mg配合・30日分・腸溶性カプセル",
    "campaign": "初回30%OFF（定期コースのみ）"
}

# コスト比較: gpt-4o vs gpt-4o-mini
for model, input_price, output_price in [("gpt-4o", 5.0, 15.0), ("gpt-4o-mini", 0.15, 0.60)]:
    req = design_copy_generation_request(product, "信頼感・親しみやすさ", "30〜40代健康意識の高い女性", model)
    input_tokens = ceil(len(json.dumps(req, ensure_ascii=False)) / 3)
    cost_per_call = (input_tokens / 1_000_000 * input_price) + (1000 / 1_000_000 * output_price)
    print(f"{model}: ${cost_per_call:.6f}/回 → 月1000件 ¥{cost_per_call*1000*150:,.0f}")
